export default function OlimpiadasSeedPage({ onBack }) {
  const [status, setStatus] = useState("");
  const [done, setDone] = useState(false);

  const executarSeed = async () => {
    if (!window.confirm("Carregar " + SEED_DATA.length + " registros no Firebase?")) return;
    setStatus("Carregando registros...");
    try {
      let count = 0;
      for (let i = 0; i < SEED_DATA.length; i++) {
        await addDoc(collection(db, "olimpiadas_escolas"), SEED_DATA[i]);
        count++;
        if (count % 10 === 0) setStatus("Carregados: " + count + "/" + SEED_DATA.length);
      }
      setStatus("✅ " + SEED_DATA.length + " registros carregados com sucesso!");
      setDone(true);
    } catch(e) {
      setStatus("❌ Erro: " + e.message);
    }
  };

  return (
    <div style={{ minHeight:"100vh", background:"#f0f2f5", fontFamily:"'Montserrat',sans-serif", display:"flex", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ background:"#fff", borderRadius:24, padding:40, maxWidth:480, width:"100%", boxShadow:"0 4px 24px rgba(27,63,122,0.1)", textAlign:"center" }}>
        <div style={{ fontSize:48, marginBottom:16 }}>🏆</div>
        <div style={{ fontWeight:900, fontSize:22, color:"#1B3F7A", marginBottom:8 }}>Seed Olímpiadas</div>
        <div style={{ color:"#888", fontSize:13, marginBottom:24 }}>Carrega {SEED_DATA.length} registros históricos (2024/2025/2026) no Firebase</div>
        {status && <div style={{ background:"#f0f9ff", borderRadius:12, padding:"12px 16px", fontSize:13, color:"#0891b2", marginBottom:16, fontWeight:600 }}>{status}</div>}
        {!done ? (
          <div onClick={executarSeed} style={{ background:"#1B3F7A", borderRadius:14, padding:"14px 32px", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", display:"inline-block" }}>🚀 Executar Seed</div>
        ) : (
          <div onClick={onBack} style={{ background:"#059669", borderRadius:14, padding:"14px 32px", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", display:"inline-block" }}>✅ Voltar ao Módulo</div>
        )}
        <div onClick={onBack} style={{ marginTop:16, fontSize:12, color:"#888", cursor:"pointer" }}>← Voltar</div>
      </div>
    </div>
  );
}
